#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_matches_filter_by_title() {
        let task = Task::new(1, "Buy groceries".to_string(), 1);
        assert!(task.matches_filter("groceries"));
        assert!(task.matches_filter("GROCERIES"));
        assert!(!task.matches_filter("laundry"));
    }

    #[test]
    fn test_matches_filter_by_tag() {
        let mut task = Task::new(2, "Review PR".to_string(), 2);
        task.tags = vec!["work".to_string(), "urgent".to_string()];
        assert!(task.matches_filter("work"));
        assert!(task.matches_filter("URGENT"));
        assert!(!task.matches_filter("personal"));
    }

    #[test]
    fn test_matches_filter_empty_string() {
        let task = Task::new(3, "Any task".to_string(), 1);
        assert!(task.matches_filter(""));
    }
}
