#[test]
fn test_filter_by_query() {
    setup_test_tasks();
    let output = run_cmd(&["filter", "--query", "groceries"]);
    assert!(output.contains("Buy groceries"));
    assert!(!output.contains("Review PR"));
}

#[test]
fn test_filter_by_tag() {
    setup_test_tasks();
    let output = run_cmd(&["filter", "--tag", "work"]);
    assert!(output.contains("Review PR"));
    assert!(!output.contains("Buy groceries"));
}

#[test]
fn test_filter_by_priority() {
    setup_test_tasks();
    let output = run_cmd(&["filter", "--priority", "3"]);
    assert!(output.contains("Deploy release"));
    assert!(!output.contains("Buy groceries"));
}

#[test]
fn test_filter_no_matches() {
    setup_test_tasks();
    let output = run_cmd(&["filter", "--query", "nonexistent"]);
    assert!(output.contains("No tasks match"));
}
